return [{ json: {
  emailTo: 'house-search@jorisjonkers.dev',
  geminiApiKey: 'KEYHERE',
  woninghurenBody: JSON.stringify({
    limit: 25, page: 0, locale: 'nl_NL',
    filters: { '$and': [
      {'municipality.name': {'$eq': 'Enschede'}},
      {'totalRent': {'$gte': 1000}},
      {'totalRent': {'$lte': 1500}},
      {'sleepingRoom.amountOfRooms': {'$gte': 3}},
      {'dwellingType.categorie': {'$ne': 'parkeerplaats'}},
      {'dwellingType.categorie': {'$ne': 'garage'}},
      {'dwellingType.categorie': {'$ne': 'berging'}}
    ]}
  }),
  parariusBody: JSON.stringify({cmd: 'request.get', url: 'https://www.pararius.nl/huurwoningen/enschede/1000-1500/3-slaapkamers', maxTimeout: 120000}),
  huurwoningenBody: JSON.stringify({cmd: 'request.get', url: 'https://www.huurwoningen.nl/in/enschede/?price=1000-1500&bedrooms=3', maxTimeout: 120000})
}}];

// Extract listings from FlareSolverr HTML responses
// Strategy: 1) Try JSON-LD structured data (Pararius has this), 2) Fall back to Gemini
const configs = $('Config').all();
const geminiApiKey = configs[0]?.json?.geminiApiKey || '';
const results = [];

const sources = [
  { node: 'Fetch Pararius', naam: 'Pararius', url: 'https://www.pararius.nl/huurwoningen/enschede/1000-1500/3-slaapkamers' },
  { node: 'Fetch Huurwoningen', naam: 'Huurwoningen.nl', url: 'https://www.huurwoningen.nl/in/enschede/?price=1000-1500&bedrooms=3' }
];

for (const src of sources) {
  try {
    const resp = $(src.node).first().json;
    const html = resp?.solution?.response || resp?.data || '';

    if (!html || html.length < 500) {
      results.push({ json: { naam: src.naam, sourceUrl: src.url, isError: true, fout: 'Geen HTML ontvangen van FlareSolverr' } });
      continue;
    }

    const domain = src.url.match(/https?:\/\/[^/]+/)?.[0] || '';
    let directListings = [];

    // --- Strategy 1: Parse JSON-LD structured data (Pararius embeds this) ---
    const jsonLdMatches = html.match(/<script[^>]*type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/gi);
    if (jsonLdMatches) {
      for (const m of jsonLdMatches) {
        try {
          const jsonStr = m.replace(/<script[^>]*>/i, '').replace(/<\/script>/i, '');
          const ld = JSON.parse(jsonStr);
          // Find ItemList with ListItems (Pararius format)
          const graph = ld['@graph'] || [ld];
          for (const node of graph) {
            const itemList = node.mainEntity?.itemListElement || node.itemListElement;
            if (!itemList) continue;
            for (const entry of itemList) {
              const item = entry.item || entry;
              const name = item.name || '';
              const url = item.url || item['@id'] || '';
              const price = item.offers?.price || 0;
              const img = item.image || null;
              if (name && url) {
                directListings.push({
                  titel: name,
                  prijs: parseInt(price) || 0,
                  kamers: null,
                  oppervlakte: null,
                  url: url.startsWith('http') ? url : domain + url,
                  afbeelding: img
                });
              }
            }
          }
        } catch (e) { /* JSON-LD parse failed, continue */ }
      }
    }

    // --- Strategy 2: Parse listing cards from HTML directly ---
    if (directListings.length === 0) {
      // Look for listing-search-item sections (Pararius/Huurwoningen pattern)
      const listingBlocks = html.split(/(?=<section[^>]*listing-search-item[^>]*>)/i);
      for (const block of listingBlocks) {
        if (block.length < 200 || block.length > 50000) continue;
        const titleMatch = block.match(/listing-search-item__link--title[^>]*href="([^"]+)"[^>]*>[\s\S]*?([^<]+)<\/a>/i)
          || block.match(/listing-search-item__title[^>]*>[\s\S]*?<a[^>]*href="([^"]+)"[^>]*>([^<]+)/i);
        const priceMatch = block.match(/listing-search-item__price[^>]*>[\s\S]*?(?:€|&euro;)\s*(?:&nbsp;)?([\d.,]+)/i)
          || block.match(/price-main[^>]*>[\s\S]*?(?:€|&euro;)\s*(?:&nbsp;)?([\d.,]+)/i);
        const areaMatch = block.match(/(\d+)\s*m[²2]/i);
        const roomsMatch = block.match(/(\d+)\s*(?:kamer|room)/i);
        const imgMatch = block.match(/picture__image[^>]*src="([^"]+)"/i)
          || block.match(/<img[^>]*src="(https:\/\/casco-media[^"]+)"/i);
        if (titleMatch) {
          const url = titleMatch[1];
          const title = titleMatch[2].trim();
          const price = priceMatch ? parseInt(priceMatch[1].replace(/\./g, '').replace(',', '.')) : 0;
          directListings.push({
            titel: title,
            prijs: price,
            kamers: roomsMatch ? parseInt(roomsMatch[1]) : null,
            oppervlakte: areaMatch ? parseInt(areaMatch[1]) : null,
            url: url.startsWith('http') ? url : domain + url,
            afbeelding: imgMatch ? imgMatch[1] : null
          });
        }
      }
    }

    // If we got listings directly, skip Gemini entirely
    if (directListings.length > 0) {
      results.push({ json: {
        naam: src.naam, sourceUrl: src.url, isError: false,
        directListings: directListings,
        needsGemini: false,
        geminiUrl: '', requestBody: '{}'
      }});
      continue;
    }

    // --- Strategy 3: Fall back to Gemini ---
    if (!geminiApiKey || geminiApiKey.length < 10) {
      results.push({ json: { naam: src.naam, sourceUrl: src.url, isError: true, fout: 'Geen listings gevonden en geen Gemini key' } });
      continue;
    }

    let cleaned = html
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, '')
      .replace(/<svg[\s\S]*?<\/svg>/gi, '')
      .replace(/<header[\s\S]*?<\/header>/gi, '')
      .replace(/<footer[\s\S]*?<\/footer>/gi, '')
      .replace(/<nav[\s\S]*?<\/nav>/gi, '')
      .replace(/<!--[\s\S]*?-->/g, '');
    const mainMatch = cleaned.match(/<main[\s\S]*<\/main>/i);
    if (mainMatch && mainMatch[0].length > 500) cleaned = mainMatch[0];
    cleaned = cleaned.substring(0, 200000);

    const prompt = `Extract ALL rental property listings from this HTML from ${src.naam}.\nReturn ONLY a JSON array: [{"titel": "address", "prijs": rent_number, "kamers": bedrooms_or_null, "oppervlakte": area_m2_or_null, "url": "absolute_url", "afbeelding": "img_url_or_null"}]\nBase domain: ${domain}\nSkip navigation, cookies, ads. Only real property listings. Return [] if none found.\n\nHTML:\n${cleaned}`;

    results.push({ json: {
      naam: src.naam, sourceUrl: src.url, isError: false,
      needsGemini: true,
      geminiUrl: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${geminiApiKey}`,
      requestBody: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], generationConfig: { maxOutputTokens: 4000, temperature: 0.1 } })
    }});
  } catch (e) {
    results.push({ json: { naam: src.naam, sourceUrl: src.url, isError: true, fout: 'Error: ' + e.message } });
  }
}

return results;

// Combine Woninghuren API results + Gemini-extracted Pararius/Huurwoningen results
const SKIP = ['parking','parkeerplaats','garage','berging','storage','garagebox','opslagruimte'];
const results = [];

// --- Woninghuren.nl (direct API) ---
try {
  const items = $('Woninghuren API').all();
  for (const item of items) {
    const d = item.json;
    const listings = Array.isArray(d) ? d : (d.result || d.data || (d.street ? [d] : []));
    if (!Array.isArray(listings)) continue;
    for (const l of listings) {
      if (!l.street) continue;
      const type = (l.dwellingType?.localizedName || l.dwellingType?.categorie || '').toLowerCase();
      if (SKIP.some(s => type.includes(s))) continue;
      const rooms = l.sleepingRoom?.amountOfRooms || 0;
      if (rooms < 3) continue;
      const addr = [l.street, l.houseNumber, l.houseNumberAddition].filter(Boolean).join(' ');
      const img = l.pictures?.[0]?.uri;
      results.push({ json: {
        bron: 'Woninghuren.nl',
        titel: addr + (l.postalcode ? ', ' + l.postalcode : '') + ' Enschede',
        prijs: '€ ' + (l.totalRent || 0),
        prijsNumeriek: l.totalRent || 0,
        kamers: rooms,
        oppervlakte: l.areaDwelling ? l.areaDwelling + ' m²' : null,
        url: 'https://www.woninghuren.nl/aanbod/te-huur/details/' + (l.urlKey || l.id || ''),
        afbeelding: img ? (img.startsWith('http') ? img : 'https://www.woninghuren.nl' + img) : null,
        scraped: new Date().toISOString()
      }});
    }
  }
} catch (e) {
  results.push({ json: { bron: 'Woninghuren.nl', fout: 'Error: ' + e.message, url: 'https://www.woninghuren.nl/aanbod/te-huur', scraped: new Date().toISOString() } });
}

// --- Pararius + Huurwoningen ---
let geminiResponses = [];
let prepItems = [];
try { geminiResponses = $('Gemini Extract').all(); } catch (e) { /* branch not executed */ }
try { prepItems = $('Prepare Gemini Extract').all(); } catch (e) { /* branch not executed */ }

for (let i = 0; i < prepItems.length; i++) {
  const prep = prepItems[i]?.json || {};
  if (prep.isError) {
    results.push({ json: { bron: prep.naam, fout: prep.fout, url: prep.sourceUrl, scraped: new Date().toISOString() } });
    continue;
  }

  let listings = [];

  // Check if we have direct listings (parsed from HTML/JSON-LD without Gemini)
  if (prep.directListings && prep.directListings.length > 0) {
    listings = prep.directListings;
  } else if (prep.needsGemini) {
    // Parse Gemini response
    try {
      const raw = geminiResponses[i]?.json?.data || JSON.stringify(geminiResponses[i]?.json) || '';
      let text = raw;
      try {
        const parsed = JSON.parse(raw);
        if (parsed.candidates) text = parsed.candidates[0]?.content?.parts?.[0]?.text || '[]';
      } catch (e) {}
      const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/```\s*$/m, '').trim();
      const m = cleaned.match(/\[[\s\S]*\]/);
      listings = m ? JSON.parse(m[0]) : [];
    } catch (e) {
      results.push({ json: { bron: prep.naam, fout: 'Gemini parse error: ' + e.message, url: prep.sourceUrl, scraped: new Date().toISOString() } });
      continue;
    }
  }

  if (listings.length === 0) {
    results.push({ json: { bron: prep.naam, fout: 'Geen woningen gevonden', url: prep.sourceUrl, scraped: new Date().toISOString() } });
    continue;
  }

  for (const l of listings) {
    const title = (l.titel || '').toLowerCase();
    if (SKIP.some(s => title.includes(s))) continue;
    if (l.kamers && l.kamers < 3) continue;
    const priceNum = parseInt(l.prijs) || 0;
    if (priceNum > 0 && (priceNum < 800 || priceNum > 1600)) continue;
    results.push({ json: {
      bron: prep.naam,
      titel: l.titel || 'Zie link',
      prijs: priceNum ? '€ ' + priceNum : 'Onbekend',
      prijsNumeriek: priceNum,
      kamers: l.kamers || null,
      oppervlakte: l.oppervlakte ? l.oppervlakte + (String(l.oppervlakte).includes('m') ? '' : ' m²') : null,
      url: l.url || prep.sourceUrl,
      afbeelding: l.afbeelding || null,
      scraped: new Date().toISOString()
    }});
  }
}

return results.length > 0 ? results : [{ json: { bron: 'Systeem', fout: 'Geen resultaten', scraped: new Date().toISOString() } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.known) staticData.known = {};

const items = $input.all();
const newListings = [];
const errors = [];
const seenUrls = new Set();
const now = new Date().toISOString();

for (const item of items) {
  const d = item.json;
  if (d.fout) { errors.push(d); continue; }
  if (!d.url || seenUrls.has(d.url)) continue;
  seenUrls.add(d.url);

  const existing = staticData.known[d.url];
  const isNew = !existing;
  const priceChanged = existing && existing.prijs !== d.prijsNumeriek && d.prijsNumeriek > 0;

  staticData.known[d.url] = {
    titel: d.titel, prijs: d.prijsNumeriek, bron: d.bron,
    eersteGezien: existing ? existing.eersteGezien : now,
    laatstGezien: now
  };

  if (isNew || priceChanged) {
    newListings.push({ ...d, isNew, priceChanged });
  }
}

// Cleanup > 30 days
const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
for (const [url, data] of Object.entries(staticData.known)) {
  if (new Date(data.laatstGezien).getTime() < cutoff) delete staticData.known[url];
}

if (newListings.length > 0) {
  return [{ json: { geenNieuws: false, listings: newListings, errors } }];
}
return [{ json: { geenNieuws: true, errors } }];

const data = $input.first().json;
const geminiApiKey = $('Config').first().json.geminiApiKey || '';

if (data.geenNieuws || !data.listings?.length) {
  return [{ json: { ...data, geminiUrl: '', requestBody: '{}' } }];
}

if (!geminiApiKey || geminiApiKey.length < 10) {
  return [{ json: { ...data, geminiUrl: '', requestBody: '{}' } }];
}

const evalList = data.listings.map((l, i) =>
  `${i+1}. ${l.titel} — ${l.prijs}/maand, ${l.kamers ? l.kamers + ' kamers' : '?'}, ${l.oppervlakte || '?'}, bron: ${l.bron}`
).join('\n');

const prompt = `Beoordeel deze huurwoningen in Enschede 1-10 op aantrekkelijkheid, leefbaarheid en prijs/kwaliteit.\nReturn ALLEEN een JSON array in dezelfde volgorde: [{"score": N, "uitleg": "max 2 zinnen NL"}, ...]\n\n${evalList}`;

return [{ json: {
  ...data,
  geminiUrl: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${geminiApiKey}`,
  requestBody: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], generationConfig: { maxOutputTokens: 2000, temperature: 0.3 } })
}}];

const prepData = $('Prepare Eval').first().json;
const listings = prepData.listings || [];
const errors = prepData.errors || [];
const emailTo = $('Config').first().json.emailTo;

if (prepData.geenNieuws || listings.length === 0) {
  return [{ json: { aantalNieuw: 0, geenNieuws: true } }];
}

// Parse Gemini scores
try {
  const raw = $input.first().json.data || JSON.stringify($input.first().json) || '';
  let text = raw;
  try {
    const parsed = JSON.parse(raw);
    if (parsed.candidates) text = parsed.candidates[0]?.content?.parts?.[0]?.text || '[]';
  } catch (e) {}
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/```\s*$/m, '').trim();
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (m) {
    const scores = JSON.parse(m[0]);
    for (let i = 0; i < Math.min(scores.length, listings.length); i++) {
      listings[i].aiScore = scores[i].score;
      listings[i].aiUitleg = scores[i].uitleg;
    }
  }
} catch (e) { /* continue without scores */ }

listings.sort((a, b) => (b.aiScore || 0) - (a.aiScore || 0) || (a.prijsNumeriek || 9999) - (b.prijsNumeriek || 9999));

const datum = new Date().toLocaleDateString('nl-NL');
let h = `<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;">`;
h += `<h2 style="color:#2c3e50;">🏠 Nieuwe huurwoningen in Enschede!</h2>`;
h += `<p style="color:#555;">Gevonden via: ${[...new Set(listings.map(l => l.bron))].join(', ')}</p>`;
h += `<p><strong>${listings.length} nieuwe/gewijzigde woning(en)</strong> op ${datum}</p>`;

const hasAi = listings.some(l => l.aiScore);
for (const l of listings) {
  const scoreColor = l.aiScore >= 7 ? '#27ae60' : l.aiScore >= 5 ? '#f39c12' : l.aiScore ? '#e74c3c' : '#999';
  const scoreEmoji = l.aiScore >= 8 ? '🌟' : l.aiScore >= 6 ? '👍' : l.aiScore >= 4 ? '👌' : l.aiScore ? '👎' : '';
  const badge = l.isNew ? '<span style="background:#27ae60;color:white;padding:2px 8px;border-radius:3px;font-size:11px;font-weight:bold;">NIEUW</span> ' : l.priceChanged ? '<span style="background:#e67e22;color:white;padding:2px 8px;border-radius:3px;font-size:11px;font-weight:bold;">PRIJS GEWIJZIGD</span> ' : '';
  h += `<div style="border:1px solid #ddd;border-radius:8px;margin:12px 0;overflow:hidden;"><table width="100%" cellpadding="0" cellspacing="0"><tr>`;
  if (l.afbeelding) h += `<td style="width:180px;vertical-align:top;"><img src="${l.afbeelding}" style="width:180px;height:130px;object-fit:cover;display:block;" alt="Foto"></td>`;
  h += `<td style="padding:12px;vertical-align:top;">`;
  h += `<div>${badge}<strong style="color:#2c3e50;font-size:16px;">${l.titel}</strong></div>`;
  h += `<p style="margin:4px 0;color:#555;font-size:13px;">${l.bron} | ${l.kamers ? l.kamers + ' kamers' : '-'} | ${l.oppervlakte || '-'}</p>`;
  h += `<p style="margin:4px 0;font-size:20px;font-weight:bold;color:#2c3e50;">${l.prijs} <span style="font-size:12px;font-weight:normal;color:#999;">/maand</span></p>`;
  if (hasAi && l.aiScore) {
    h += `<div style="margin:4px 0;padding:4px 8px;background:#f8f9fa;border-radius:4px;font-size:13px;display:inline-block;"><span style="color:${scoreColor};font-weight:bold;">${scoreEmoji} ${l.aiScore}/10</span>`;
    if (l.aiUitleg) h += ` — <em>${l.aiUitleg}</em>`;
    h += `</div>`;
  }
  h += `<div style="margin-top:8px;"><a href="${l.url}" style="display:inline-block;padding:6px 16px;background:#3498db;color:white;text-decoration:none;border-radius:4px;font-size:13px;">Bekijk woning →</a></div>`;
  h += `</td></tr></table></div>`;
}

if (errors.length > 0) {
  h += `<h3 style="color:#e67e22;">⚠️ Waarschuwingen</h3><ul style="color:#555;font-size:13px;">`;
  for (const e of errors) {
    h += `<li><strong>${e.bron}:</strong> ${e.fout}`;
    if (e.url) h += ` — <a href="${e.url}">Handmatig zoeken</a>`;
    h += `</li>`;
  }
  h += `</ul>`;
}

h += `<h3 style="color:#2c3e50;">🔗 Directe zoeklinks</h3><ul style="font-size:13px;">`;
h += `<li><a href="https://www.woninghuren.nl/aanbod/te-huur#?locatie=Enschede&huurprijs=1000&huurprijs=1500&aantal-slaapkamers=3">Woninghuren.nl</a></li>`;
h += `<li><a href="https://www.pararius.nl/huurwoningen/enschede/1000-1500/3-slaapkamers">Pararius.nl</a></li>`;
h += `<li><a href="https://www.huurwoningen.nl/in/enschede/?price=1000-1500&bedrooms=3">Huurwoningen.nl</a></li>`;
h += `<li><a href="https://www.funda.nl/zoeken/huur?selected_area=[%22enschede%22]&price=%221000-1500%22&bedrooms=%223-%22">Funda.nl (handmatig)</a></li>`;
h += `</ul>`;
h += `<p style="color:#999;font-size:11px;">Gegenereerd op ${new Date().toLocaleString('nl-NL')} door n8n Huurwoning Scraper v2</p></div>`;

return [{ json: { aantalNieuw: listings.length, emailOnderwerp: `🏠 ${listings.length} nieuwe huurwoning(en) in Enschede — ${datum}`, emailHtml: h, emailTo } }];
